const email = $input.first().json;

// Debug : logguer toutes les clefs pour comprendre le format Gmail Trigger
console.log('[02] Clefs email:', Object.keys(email).join(', '));
console.log('[02] to:', JSON.stringify(email.to));
console.log('[02] from:', JSON.stringify(email.from));
console.log('[02] headers:', JSON.stringify(email.headers));
console.log('[02] labelIds:', JSON.stringify(email.labelIds));

// Extraire les adresses email de maniere robuste
// Gmail Trigger peut renvoyer : string, objet {value: [{address, name}]}, ou tableau
function extractEmail(field) {
  if (!field) return '';
  if (typeof field === 'string') return field;
  if (field.text) return field.text;
  if (field.value && Array.isArray(field.value)) return field.value.map(v => v.address || v.name || '').join(', ');
  if (Array.isArray(field)) return field.map(f => typeof f === 'string' ? f : (f.address || f.text || '')).join(', ');
  if (field.address) return field.address;
  return JSON.stringify(field);
}

const fromStr = extractEmail(email.from);
const toStr = extractEmail(email.to);

// Chercher le tenantId dans TOUTES les adresses du mail
const TENANT_MAP = {
  'direction@talosprimes.com': 'efbf3d9e-6ccc-44a3-ad41-dc4093ecc227'
};

const allAddresses = (fromStr + ' ' + toStr + ' ' + (email.delivered_to || '') + ' ' + JSON.stringify(email.headers || {})).toLowerCase();
console.log('[02] Toutes les adresses:', allAddresses.substring(0, 300));

let tenantId = null;
for (const [addr, tid] of Object.entries(TENANT_MAP)) {
  if (allAddresses.includes(addr.toLowerCase())) { tenantId = tid; break; }
}

// Erreur explicite si aucun tenant trouve — PAS de fallback
if (!tenantId) {
  throw new Error('[02] TENANT_MAP: aucun match pour les adresses: ' + allAddresses.substring(0, 200) + '. Ajouter l adresse dans TENANT_MAP.');
}

console.log('[02] tenantId resolu:', tenantId);

return [{ json: {
  id: email.id || email.messageId || null,
  threadId: email.threadId || null,
  from: fromStr,
  to: toStr,
  subject: email.subject || '(sans objet)',
  date: email.date || email.internalDate || new Date().toISOString(),
  snippet: email.snippet || '',
  textPlain: (email.textPlain || email.text || email.snippet || '').substring(0, 1000),
  labels: email.labelIds || [],
  hasAttachments: (email.attachments || []).length > 0,
  tenantId: tenantId,
  action: 'received'
} }];

